package com.evernorth.smartemp.controller; import com.evernorth.smartemp.dto.EmployeeDto; import com.evernorth.smartemp.service.EmployeeService; import jakarta.validation.Valid; import lombok.RequiredArgsConstructor; import org.springframework.http.*; import org.springframework.web.bind.annotation.*;
@RestController @RequestMapping("/api/admin/employees") @RequiredArgsConstructor public class AdminEmployeeController{private final EmployeeService s;private final com.evernorth.smartemp.repository.UserRepository users;@PostMapping public ResponseEntity<EmployeeDto.Response> create(@Valid@RequestBody EmployeeDto.Request r){return ResponseEntity.status(HttpStatus.CREATED).body(s.create(r));}@PutMapping("/{id}")public ResponseEntity<EmployeeDto.Response> update(@PathVariable Long id,@Valid@RequestBody EmployeeDto.Request r){return ResponseEntity.ok(s.update(id,r));}@DeleteMapping("/{id}")public ResponseEntity<Void> delete(@PathVariable Long id){s.delete(id);return ResponseEntity.noContent().build();}@GetMapping("/pending") public Object pending(){return users.findByApprovedFalseOrderByIdAsc();}@PostMapping("/{id}/approve") public ResponseEntity<Void> approve(@PathVariable Long id){var u=users.findById(id).orElseThrow();u.setApproved(true);users.save(u);return ResponseEntity.noContent().build();}}
